380→async fn run_turn(
381→    cli: &Cli,
382→    client: &AnthropicClient,
383→    system_prompt: &str,
384→    tools: &[serde_json::Value],
385→    conversation: &mut Vec<Message>,
386→    session: &mut SessionWriter,
387→    hooks: &HookRunner,
388→    input: &str,
389→) {
390→    // Add user message
391→    let user_msg = Message {
392→        role: "user".to_string(),
393→        content: vec![ContentBlock::Text {
394→            text: input.to_string(),
395→        }],
396→    };
397→    conversation.push(user_msg.clone());
398→    session.append_user_turn(&user_msg);
399→    session.write_prompt(input);
400→
401→    let mut tool_iterations: usize = 0;
402→    let mut continuation_count: usize = 0;
403→    let mut last_input_tokens: u64 = 0;
404→    let mut consecutive_block_count: usize = 0;
405→    let mut total_block_count: usize = 0;
406→    let mut total_tokens: u64 = 0;
407→    let mut stop_reason_str = "end_turn";
408→
409→    // Inner loop: call API, dispatch tools, repeat
410→    loop {
411→        // Token-aware trim: first call (no data) uses byte safety net;
412→        // subsequent calls skip trim when under threshold.
413→        trim_if_needed(conversation, last_input_tokens);
414→
415→        if tool_iterations >= MAX_TOOL_ITERATIONS {
416→            eprintln!("[warn] Tool iteration limit ({MAX_TOOL_ITERATIONS}) reached");
417→            recover_conversation(conversation);
418→            stop_reason_str = "iteration_limit";
419→            break;
420→        }
421→
422→        // Retry loop wrapping the API call
423→        // attempt 0 = initial call, 1..=MAX_RETRIES = retries
424→        let mut api_result = None;
425→        #[allow(clippy::needless_range_loop)]
426→        for attempt in 0..=MAX_RETRIES {
427→            let result = client
428→                .send_message(
429→                    &cli.model,
430→                    cli.max_tokens,
431→                    system_prompt,
432→                    conversation,
433→                    tools,
434→                    &mut |text| {
435→                        print!("{text}");
436→                        io::stdout().flush().ok();
437→                    },
438→                )
439→                .await;
440→
441→            match result {
442→                Ok(r) => {
443→                    api_result = Some(r);
444→                    break;
445→                }
446→                Err(e) => {
447→                    eprintln!("\n[error] API call failed: {e}");
448→
449→                    if classify_error(&e) == ErrorClass::Permanent {
450→                        recover_conversation(conversation);
451→                        stop_reason_str = "api_error";
452→                        break;
453→                    }
454→
455→                    // Transient error — retry if attempts remain
456→                    if attempt >= MAX_RETRIES {
457→                        eprintln!("[retry] Max retries ({MAX_RETRIES}) exhausted");
458→                        recover_conversation(conversation);
459→                        stop_reason_str = "api_error";
460→                        break;
461→                    }
462→
463→                    // Determine delay: retry-after header overrides backoff
464→                    let delay = if let AgentError::HttpError {
465→                        retry_after: Some(ra),
466→                        ..
467→                    } = &e
468→                    {
469→                        let capped = (*ra).min(RETRY_AFTER_CAP);
470→                        eprintln!("[retry] Using retry-after: {capped}s");
471→                        capped
472→                    } else {
473→                        BACKOFF_SCHEDULE[attempt]
474→                    };
475→
476→                    if matches!(e, AgentError::StreamTransient(_)) {
477→                        eprintln!("[retry] Retrying from beginning of response...");
478→                    }
479→
480→                    eprintln!(
481→                        "[retry] Attempt {}/{MAX_RETRIES}: {} — waiting {delay}s",
482→                        attempt + 1,
483→                        e
484→                    );
485→                    tokio::time::sleep(std::time::Duration::from_secs(delay)).await;
486→                }
487→            }
488→        }
489→
490→        let (blocks, stop_reason, usage) = match api_result {
491→            Some(r) => r,
492→            None => break, // All retries failed or permanent error
493→        };
494→
495→        // Update token tracking for next trim decision
496→        last_input_tokens = usage.input_tokens;
497→        total_tokens += usage.input_tokens + usage.output_tokens;
498→
499→        if cli.verbose {
500→            eprintln!(
501→                "[verbose] Cache: {} read, {} created, {} total input",
502→                usage.cache_read_input_tokens,
503→                usage.cache_creation_input_tokens,
504→                usage.input_tokens
505→            );
506→        }
507→
508→        // Filter null-input tool_use blocks on MaxTokens truncation
509→        let blocks = if stop_reason == StopReason::MaxTokens {
510→            filter_null_input_tool_use(blocks)
511→        } else {
512→            blocks
513→        };
514→
515→        // Add assistant response to conversation
516→        let assistant_msg = Message {
517→            role: "assistant".to_string(),
518→            content: blocks.clone(),
519→        };
520→        conversation.push(assistant_msg.clone());
521→        session.append_assistant_turn(&assistant_msg, &usage);
522→
523→        // --- Canonical three-way branch ---
524→
525→        // 1. EndTurn — normal completion
526→        if stop_reason == StopReason::EndTurn {
527→            println!();
528→            stop_reason_str = "end_turn";
529→            break;
530→        }
531→
532→        // 2. MaxTokens — filter, then decide: continue, dispatch tools, or break
533→        if stop_reason == StopReason::MaxTokens {
534→            println!();
