                        total_block_count += 1;

                        if consecutive_block_count >= MAX_CONSECUTIVE_BLOCKS {
                            eprintln!(
                                "[hooks] Consecutive block limit ({MAX_CONSECUTIVE_BLOCKS}) reached"
                            );
