869→fn truncate_json(value: &serde_json::Value, max_len: usize) -> String {
870→    let s = value.to_string();
871→    if s.len() <= max_len {
872→        s
873→    } else {
874→        format!("{}...", &s[..s.floor_char_boundary(max_len)])
875→    }
876→}
