878→const MAX_CONTINUATIONS: usize = 3;
879→
880→/// Determine what to do after a MaxTokens stop_reason.
881→/// Returns the action to take given the filtered content blocks and current continuation count.
882→#[derive(Debug, PartialEq)]
883→enum MaxTokensAction {
884→    /// Response was empty (only placeholder) — break immediately
885→    BreakEmpty,
886→    /// Valid tool_use blocks present — fall through to tool dispatch
887→    DispatchTools,
888→    /// Text-only, under cap — inject continuation prompt
889→    Continue,
890→    /// Text-only, cap reached — break
891→    BreakCapReached,
892→}
893→
894→fn classify_max_tokens(blocks: &[ContentBlock], continuation_count: usize) -> MaxTokensAction {
895→    // Check for empty response (only the "[Response truncated]" placeholder)
896→    let is_empty = blocks.len() == 1
897→        && matches!(&blocks[0], ContentBlock::Text { text } if text == "[Response truncated]");
898→    if is_empty {
899→        return MaxTokensAction::BreakEmpty;
900→    }
901→
902→    let has_valid_tools = blocks
903→        .iter()
904→        .any(|b| matches!(b, ContentBlock::ToolUse { .. }));
905→
906→    if has_valid_tools {
907→        MaxTokensAction::DispatchTools
908→    } else if continuation_count < MAX_CONTINUATIONS {
909→        MaxTokensAction::Continue
910→    } else {
911→        MaxTokensAction::BreakCapReached
912→    }
913→}
