        // One failing Read should not prevent other Reads from completing
        let dir = std::env::temp_dir().join("forgeflare_parallel_error_test");
        let _ = std::fs::create_dir_all(&dir);
        std::fs::write(dir.join("exists.txt"), "hello").unwrap();

        let inputs = vec![
