                slots[i] = Some(cb);
                blocked_flags[i] = true;
            }
            PreDispatchResult::ThresholdTripped => {
                threshold_tripped = true;
                threshold_reason = if consecutive_block_count >= MAX_CONSECUTIVE_BLOCKS {
                    "block_limit_consecutive"
                } else {
                    "block_limit_total"
                };
                break;
            }
        }
    }

    // Join all spawned futures (required even on threshold trip)
    let handles: Vec<_> = spawn_futures
        .into_iter()
        .map(|(idx, h)| async move { (idx, h.await) })
        .collect();
    let results = futures_util::future::join_all(handles).await;
    for (idx, result) in results {
        slots[idx] = Some(match result {
            Ok(block) => block,
            Err(_) => ContentBlock::ToolResult {
                tool_use_id: tool_uses[idx].0.clone(),
                content: "tool panicked".to_string(),
                is_error: Some(true),
            },
        });
    }

    if threshold_tripped {
        Vec::new() // placeholder, won't be used
    } else {
        // Post-dispatch for non-blocked tools
        for (i, (_, name, input)) in tool_uses.iter().enumerate() {
            if blocked_flags[i] {
                continue;
            }
            if let Some(ContentBlock::ToolResult {
                ref content,
                is_error,
                ..
            }) = slots[i]
            {
                let is_err = is_error.unwrap_or(false);
                if run_post_dispatch(
                    hooks,
                    name,
                    input,
                    content,
                    is_err,
                    tool_iterations,
                    cli.verbose,
                )
                .await
                {
                    signal_break = true;
                }
            }
        }

        slots.into_iter().map(|s| s.unwrap()).collect()
    }
} else {
    // Sequential path: any Mutating tool in the batch
    let mut tool_results: Vec<ContentBlock> = Vec::new();

    for (id, name, input) in &tool_uses {
        match run_pre_dispatch(
            hooks,
            id,
            name,
            input,
            tool_iterations,
            &mut consecutive_block_count,
            &mut total_block_count,
        )
        .await
        {
            PreDispatchResult::Allow => {}
            PreDispatchResult::Blocked(cb) => {
                tool_results.push(cb);
                continue;
            }
            PreDispatchResult::ThresholdTripped => {
                threshold_tripped = true;
                threshold_reason = if consecutive_block_count >= MAX_CONSECUTIVE_BLOCKS {
                    "block_limit_consecutive"
                } else {
                    "block_limit_total"
                };
                break;
            }
        }

        if cli.verbose {
            eprintln!("\n[tool] {name}({})", truncate_json(input, 100));
        } else {
            eprintln!("\n[tool] {name}");
        }

        let result = dispatch_tool(name, input, &mut |text| {
            if cli.verbose {
                eprint!("{text}");
            }
        });

        let (content, is_error) = match result {
            Ok(output) => (output, false),
            Err(err) => (err, true),
        };

        if run_post_dispatch(
            hooks,
            name,
            input,
            &content,
            is_error,
            tool_iterations,
            cli.verbose,
        )
        .await
        {
            signal_break = true;
        }

        tool_results.push(ContentBlock::ToolResult {
            tool_use_id: id.clone(),
            content,
            is_error: if is_error { Some(true) } else { None },
        });
    }

    tool_results
};

