                    assert_eq!(filename, "CLAUDE.md");
                    assert!(
                        reason.contains("ermission") || reason.contains("denied"),
                        "reason should mention permission: {}",
                        reason
                    );
                }
                other => panic!("expected Skipped, got {:?}", other),
            }
        });
    }

    #[cfg(unix)]
