            match result {
                InstructionsResult::Found { filename, contents } => {
                    assert_eq!(filename, "CLAUDE.md");
                    assert_eq!(contents, "build instructions here");
                }
                other => panic!("expected Found, got {:?}", other),
            }
        });
    }

