            // Restore permissions so tempdir cleanup works
            std::fs::set_permissions(&path, std::fs::Permissions::from_mode(0o644)).unwrap();
            match result {
                InstructionsResult::Skipped { filename, reason } => {
                    assert_eq!(filename, "CLAUDE.md");
