        with_temp_cwd(|dir| {
            std::fs::write(dir.join("CLAUDE.md"), "claude wins").unwrap();
            std::fs::write(dir.join("AGENTS.md"), "agents loses").unwrap();
            let result = load_project_instructions();
            match result {
