        with_temp_cwd(|dir| {
            let big = "x".repeat(PROJECT_INSTRUCTIONS_MAX_BYTES + 1);
            std::fs::write(dir.join("CLAUDE.md"), &big).unwrap();
            std::fs::write(dir.join("AGENTS.md"), "fallback agents").unwrap();
            let result = load_project_instructions();
            match result {
