    }

    #[cfg(unix)]
    #[test]
    fn instructions_unreadable_file_skipped() {
        // File exists but no read permission — produces Skipped, falls through.
        use std::os::unix::fs::PermissionsExt;
        with_temp_cwd(|dir| {
